package org.contentcatalyst.algorithms; public class ConsensusAudit{static int mq(int n){return n/2+1;} static int ft(int n){return (n-1)/2;} static int bft(int f){return 3*f+1;} public static void main(String[] args){System.out.println("test_name,value");System.out.println("majority_quorum_5_nodes,"+mq(5));System.out.println("crash_fault_tolerance_5_nodes,"+ft(5));System.out.println("byzantine_replicas_for_2_faults,"+bft(2));}}
